class PlayerConnection:
    """Represents a single player's TCP connection."""

    def __init__(self, sock, address, player_name='Unknown'):
        self.socket = sock
        self.address = address
        self.player_name = player_name

    def send(self, message):
        try:
            self.socket.sendall(message.encode('utf-8'))
        except OSError:
            pass


class MUDServer:
    """A TCP server for the Multi-User Dungeon."""

    def __init__(self, host='127.0.0.1', port=7777):
        self.host = host
        self.port = port
        self._running = False
        self._socket = None
        self.connections = []

    @property
    def is_running(self):
        return self._running

    def start(self):
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._socket.bind((self.host, self.port))
        self._socket.listen(5)
        self._running = True

    def stop(self):
        self._running = False
        for conn in self.connections:
            try:
                conn.socket.close()
            except OSError:
                pass
        self.connections.clear()
        if self._socket:
            try:
                self._socket.close()
            except OSError:
                pass
            self._socket = None

    def add_connection(self, player_conn):
        self.connections.append(player_conn)

    def remove_connection(self, player_conn):
        if player_conn in self.connections:
            self.connections.remove(player_conn)

    def broadcast(self, message):
        for conn in list(self.connections):
            try:
                conn.send(message)
            except OSError:
                pass


class ConnectionManager:
    """Thread-safe manager for player connections."""

    def __init__(self):
        self._players = {}
        self._lock = threading.Lock()

    def add_player(self, connection):
        with self._lock:
            self._players[connection.player_name] = connection

    def remove_player(self, name):
        with self._lock:
            self._players.pop(name, None)

    def get_player(self, name):
        with self._lock:
            return self._players.get(name)

    def get_all_players(self):
        with self._lock:
            return list(self._players.values())

    @property
    def player_count(self):
        with self._lock:
            return len(self._players)


class Room:
    """A single room in the MUD world."""

    def __init__(self, name, description, exits=None, items=None, npcs=None):
        self.name = name
        self.description = description
        self.exits = exits or {}
        self.items = items or []
        self.npcs = npcs or []
        self.players_here = set()

    def add_player(self, player_name):
        self.players_here.add(player_name)

    def remove_player(self, player_name):
        self.players_here.discard(player_name)

    def get_exit(self, direction):
        return self.exits.get(direction)


class Zone:
    """A collection of related rooms."""

    def __init__(self, name):
        self.name = name
        self.rooms = {}

    def add_room(self, room):
        self.rooms[room.name] = room

    def get_room(self, room_name):
        return self.rooms.get(room_name)


class World:
    """The entire MUD world, composed of zones and rooms."""

    def __init__(self):
        self._zones = {}
        self._rooms = {}

    def add_zone(self, zone):
        self._zones[zone.name] = zone
        for room_name, room in zone.rooms.items():
            self._rooms[room_name] = room

    def get_room(self, room_name):
        return self._rooms.get(room_name)

    def move_player(self, player_name, direction, current_room_name):
        current_room = self.get_room(current_room_name)
        if current_room is None:
            return None
        dest_name = current_room.get_exit(direction)
        if dest_name is None:
            return None
        dest_room = self.get_room(dest_name)
        if dest_room is None:
            return None
        current_room.remove_player(player_name)
        dest_room.add_player(player_name)
        return dest_room

    @property
    def room_count(self):
        return len(self._rooms)


class MUDParser:
    """Parses player text input into MUD commands."""

    COMMANDS = {
        'look': r'^look$',
        'go': r'^go\s+(?P<direction>\w+)$',
        'say': r'^say\s+(?P<message>.+)$',
        'tell': r'^tell\s+(?P<player>\w+)\s+(?P<message>.+)$',
        'take': r'^take\s+(?P<item>.+)$',
        'drop': r'^drop\s+(?P<item>.+)$',
        'inventory': r'^inventory$',
        'who': r'^who$',
        'emote': r'^emote\s+(?P<action>.+)$',
        'attack': r'^attack\s+(?P<target>\w+)$',
        'help': r'^help$',
    }

    def __init__(self):
        self._patterns = [(name, re.compile(pat, re.IGNORECASE))
                          for name, pat in self.COMMANDS.items()]

    def parse(self, input_str):
        cleaned = input_str.strip()
        for cmd_name, pattern in self._patterns:
            match = pattern.match(cleaned)
            if match:
                return (cmd_name, match.groupdict())
        return ('unknown', {'input': input_str.strip()})


class ChatChannel:
    """A named chat channel with membership and message history."""

    def __init__(self, name):
        self.name = name
        self.members = set()
        self.history = deque(maxlen=100)

    def join(self, player_name):
        self.members.add(player_name)

    def leave(self, player_name):
        self.members.discard(player_name)

    def send(self, player_name, message):
        formatted = f'[{self.name}] {player_name}: {message}'
        self.history.append(formatted)

    def get_history(self, count=10):
        return list(self.history)[-count:]

    @property
    def member_count(self):
        return len(self.members)


class ChannelManager:
    """Manages chat channels for the MUD."""

    DEFAULT_CHANNELS = ['global', 'trade', 'help']

    def __init__(self):
        self._channels = {}
        for name in self.DEFAULT_CHANNELS:
            self.create_channel(name)

    def create_channel(self, name):
        channel = ChatChannel(name)
        self._channels[name] = channel
        return channel

    def get_channel(self, name):
        return self._channels.get(name)

    def list_channels(self):
        return sorted(self._channels.keys())


class Character:
    """A player character with stats and leveling."""

    def __init__(self, name, char_class, health, attack, defense):
        self.name = name
        self.char_class = char_class
        self.level = 1
        self.health = health
        self.max_health = health
        self.attack = attack
        self.defense = defense
        self.experience = 0
        self.gold = 0

    def gain_exp(self, amount):
        self.experience += amount
        while self.experience >= self.level * 100:
            self.level_up()

    def level_up(self):
        self.level += 1
        self.max_health += 10
        self.health = self.max_health
        self.attack += 2
        self.defense += 1

    def is_alive(self):
        return self.health > 0

    def take_damage(self, amount):
        self.health = max(0, self.health - amount)

    def heal(self, amount):
        self.health = min(self.max_health, self.health + amount)


class CharacterCreator:
    """Creates new characters with class-specific base stats."""

    CLASS_STATS = {
        'warrior': {'health': 120, 'attack': 15, 'defense': 12},
        'mage':    {'health': 80,  'attack': 20, 'defense': 8},
        'rogue':   {'health': 100, 'attack': 18, 'defense': 10},
    }

    def create(self, name, char_class):
        stats = self.CLASS_STATS.get(char_class)
        if stats is None:
            raise ValueError(f'Unknown character class: {char_class}')
        return Character(name, char_class, stats['health'], stats['attack'], stats['defense'])


class NPC:
    """A non-player character with dialogue and optional merchant inventory."""

    def __init__(self, name, dialogue=None, inventory=None, is_merchant=False):
        self.name = name
        self.dialogue = dialogue or {}
        self.inventory = inventory or []
        self.is_merchant = is_merchant

    def get_response(self, keyword):
        return self.dialogue.get(keyword, f'{self.name} has nothing to say about that.')

    def get_item(self, item_name):
        return next((item for item in self.inventory if item['name'] == item_name), None)


class NPCManager:
    """Manages NPC definitions and interactions."""

    def __init__(self):
        self._npcs = {}

    def load_npcs(self, definitions):
        for defn in definitions:
            npc = NPC(
                name=defn['name'],
                dialogue=defn.get('dialogue', {}),
                inventory=defn.get('inventory', []),
                is_merchant=defn.get('is_merchant', False)
            )
            self._npcs[npc.name] = npc

    def get_npc(self, name):
        return self._npcs.get(name)

    def interact(self, npc_name, keyword):
        npc = self.get_npc(npc_name)
        if npc is None:
            return None
        return npc.get_response(keyword)

    def buy(self, npc_name, item_name, player_gold):
        npc = self.get_npc(npc_name)
        if npc is None:
            return (False, 'NPC not found.', 0)
        if not npc.is_merchant:
            return (False, f'{npc.name} is not a merchant.', 0)
        item = npc.get_item(item_name)
        if item is None:
            return (False, f'{item_name} is not for sale.', 0)
        if player_gold < item['price']:
            return (False, 'Not enough gold.', 0)
        return (True, f'Purchased {item_name}.', item['price'])

    def sell(self, npc_name, item_name, base_price):
        npc = self.get_npc(npc_name)
        if npc is None:
            return (False, 'NPC not found.', 0)
        if not npc.is_merchant:
            return (False, f'{npc.name} is not a merchant.', 0)
        sell_price = base_price // 2
        return (True, f'Sold {item_name}.', sell_price)


class MUDDatabase:
    """SQLite database for persisting MUD character data."""

    def __init__(self, db_path):
        self.db_path = db_path
        self._init_db()

    def _connect(self):
        return sqlite3.connect(self.db_path)

    def _init_db(self):
        with self._connect() as conn:
            conn.execute('''CREATE TABLE IF NOT EXISTS characters (
                name TEXT PRIMARY KEY, class TEXT, level INTEGER,
                health INTEGER, max_health INTEGER, attack INTEGER,
                defense INTEGER, experience INTEGER, gold INTEGER, room TEXT
            )''')
            conn.execute('''CREATE TABLE IF NOT EXISTS inventory (
                char_name TEXT, item_name TEXT, quantity INTEGER
            )''')

    def save_character(self, character, room_name='town_square'):
        with self._connect() as conn:
            conn.execute(
                'INSERT OR REPLACE INTO characters VALUES (?,?,?,?,?,?,?,?,?,?)',
                (character.name, character.char_class, character.level,
                 character.health, character.max_health, character.attack,
                 character.defense, character.experience, character.gold, room_name)
            )

    def load_character(self, name):
        with self._connect() as conn:
            row = conn.execute('SELECT * FROM characters WHERE name=?', (name,)).fetchone()
            if row is None:
                return None
            return {
                'name': row[0], 'class': row[1], 'level': row[2],
                'health': row[3], 'max_health': row[4], 'attack': row[5],
                'defense': row[6], 'experience': row[7], 'gold': row[8], 'room': row[9]
            }

    def delete_character(self, name):
        with self._connect() as conn:
            conn.execute('DELETE FROM inventory WHERE char_name=?', (name,))
            conn.execute('DELETE FROM characters WHERE name=?', (name,))

    def list_characters(self):
        with self._connect() as conn:
            rows = conn.execute('SELECT name FROM characters').fetchall()
            return [row[0] for row in rows]

    def save_inventory(self, char_name, items):
        with self._connect() as conn:
            conn.execute('DELETE FROM inventory WHERE char_name=?', (char_name,))
            for item_name, quantity in items:
                conn.execute('INSERT INTO inventory VALUES (?,?,?)',
                             (char_name, item_name, quantity))

    def load_inventory(self, char_name):
        with self._connect() as conn:
            rows = conn.execute(
                'SELECT item_name, quantity FROM inventory WHERE char_name=?',
                (char_name,)
            ).fetchall()
            return [(row[0], row[1]) for row in rows]


class Monster:
    """A monster that can be fought and drops loot."""

    def __init__(self, name, health, attack, defense, loot_table=None, respawn_time=60):
        self.name = name
        self.health = health
        self.max_health = health
        self.attack = attack
        self.defense = defense
        self.loot_table = loot_table or []
        self.respawn_time = respawn_time

    def is_alive(self):
        return self.health > 0

    def take_damage(self, amount):
        self.health = max(0, self.health - amount)

    def respawn(self):
        self.health = self.max_health


class SpawnManager:
    """Manages monster spawning and positions in rooms."""

    def __init__(self):
        self._spawns = {}
        self._dead = []

    def spawn_monster(self, monster, room_name):
        if room_name not in self._spawns:
            self._spawns[room_name] = []
        self._spawns[room_name].append(monster)

    def get_monsters(self, room_name):
        return [m for m in self._spawns.get(room_name, []) if m.is_alive()]

    def mark_dead(self, monster, room_name):
        if room_name in self._spawns:
            if monster in self._spawns[room_name]:
                self._spawns[room_name].remove(monster)
        self._dead.append((monster, room_name, time.time()))

    def get_pending_respawns(self):
        return [(m, r) for m, r, t in self._dead]

    @property
    def total_spawns(self):
        return sum(len(monsters) for monsters in self._spawns.values())


class CombatEngine:
    """Handles combat calculations between characters and monsters."""

    def attack(self, attacker, defender):
        damage = max(1, attacker.attack - defender.defense)
        defender.take_damage(damage)
        return damage

    def drop_loot(self, monster):
        if not monster.loot_table:
            return None
        return random.choice(monster.loot_table)

    def log_combat(self, attacker_name, defender_name, damage):
        pid = os.getpid()
        platform = sys.platform
        return f'[PID:{pid}|{platform}] {attacker_name} hit {defender_name} for {damage} damage'


